import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{i,n as a,r as o,t as s}from"./chunks/windows-wizard-screenshot.QBlzzreT.js";const c=JSON.parse(`{"title":"Instalar Java en Windows","description":"Una guía paso a paso sobre como instalar Java en Windows.","frontmatter":{"title":"Instalar Java en Windows","description":"Una guía paso a paso sobre como instalar Java en Windows.","authors":["IMB11"],"files":[]},"headers":[],"relativePath":"es_es/1.21.1/players/installing-java/windows.md","filePath":"versions/1.21.1/translated/es_es/players/installing-java/windows.md","lastUpdated":1761424914000}`);var l={name:`es_es/1.21.1/players/installing-java/windows.md`};function u(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Instalar Java en Windows <a class="header-anchor" href="#h1" aria-label="Permalink to “Instalar Java en Windows”">​</a></h1><p>Esta guía te enseñará como instalar Java 17 en Windows.</p><p>El launcher de Minecraft viene con su propia instalación de Java, por lo que esta sección solo es relevante si quieres usar el instalador de Fabric <code>.jar</code>, o si quieres usar el <code>.jar</code> del Servidor de Minecraft.</p><h2 id="_1-verifica-si-java-ya-esta-instalado" tabindex="-1">1. Verifica si Java ya está instalado <a class="header-anchor" href="#_1-verifica-si-java-ya-esta-instalado" aria-label="Permalink to “1. Verifica si Java ya está instalado”">​</a></h2><p>Para comprobar si Java ya está instalado, primero debes abrir la línea de comandos.</p><p>Puedes abrirla presionando <kbd>Win</kbd>+<kbd>R</kbd> y escribiendo <code>cmd.exe</code> en la caja de texto que aparece.</p><p><img src="/assets/players/installing-java/windows-run-dialog.png" alt="Diálogo de Ejecución de Windows con &quot;cmd.exe&quot; en la barra de ejecución" loading="lazy"></p><p>Una vez abierta la línea de comandos, escribe <code>java -version</code> y presiona <kbd>Enter</kbd>.</p><p>Si el comando corre exitosamente, verás algo similar a esto. Si el comando falla, procede al siguiente paso.</p><p><img src="/assets/players/installing-java/windows-java-version.png" alt="Línea de comandos con &quot;java -version&quot; escrito" loading="lazy"></p><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Para usar la mayoría de las versiones modernas de Minecraft, necesitarás Java 17 instalado como mínimo. Si el comando muestra cualquier versión menor a 17, necesitarás actualizar tu instalación de Java existente.</p></div><h2 id="_2-descarga-el-instalador-de-java-17" tabindex="-1">2. Descarga el instalador de Java 17 <a class="header-anchor" href="#_2-descarga-el-instalador-de-java-17" aria-label="Permalink to “2. Descarga el instalador de Java 17”">​</a></h2><p>Para instalar Java 17, debes descargar el instalar desde <a href="https://adoptium.net/en-GB/temurin/releases/?os=windows&amp;package=jdk&amp;version=17" target="_blank" rel="noreferrer">Adoptium</a>.</p><p>Querrás descargar la versión <code>Windows Installer (.msi)</code>:</p><p><img src="/assets/players/installing-java/windows-download-java.png" alt="Página de descargas de Adoptium con el Windows Installer (.msi) remarcado" loading="lazy"></p><p>Escoge <code>x86</code> si tienes un sistema operativo de 32 bits, o <code>x64</code> si tienes un sistema operativo de 64 bits.</p><p>La mayoría de las computadoras modernas tienen un sistema operativo de 64 bits. Si no estás seguro, intenta con la descarga de 64 bits.</p><h2 id="_3-¡corre-el-instalador" tabindex="-1">3. ¡Corre el instalador! <a class="header-anchor" href="#_3-¡corre-el-instalador" aria-label="Permalink to “3. ¡Corre el instalador!”">​</a></h2><p>Sigue los pasos del instalador para instalar Java 17. Cuando llegues a esta página, debes elegir la opción de &quot;La funcionalidad entera será instalada en el disco duro local&quot; para las siguientes funcionalidades:</p><ul><li><code>Set JAVA_HOME environment variable</code> - Esto será agregado a tu PATH.</li><li><code>JavaSoft (Oracle) registry keys</code></li></ul><p><img src="/assets/players/installing-java/windows-wizard-screenshot.png" alt="Instalador de Java 17 con &quot;Set JAVA_HOME variable&quot; y &quot;JavaSoft (Oracle) registry keys&quot; remarcados" loading="lazy"></p><p>Una vez terminado, puedes hacer clic en <code>Next</code> y continuar con la instalación.</p><h2 id="_4-verificar-si-java-17-ya-esta-instalado" tabindex="-1">4. Verificar si Java 17 ya está instalado <a class="header-anchor" href="#_4-verificar-si-java-17-ya-esta-instalado" aria-label="Permalink to “4. Verificar si Java 17 ya está instalado”">​</a></h2><p>Una vez terminada la instalación, puedes verificar si Java 17 está instalado abriendo la línea de comandos de nuevo y escribiendo <code>java -version</code>.</p><p>Si el comando corre exitosamente, verás algo similar a lo mostrado antes, donde la versión de Java se muestra:</p><p><img src="/assets/players/installing-java/windows-java-version.png" alt="Línea de comandos con &quot;java -version&quot; escrito" loading="lazy"></p><p>Si encuentras problemas, puedes pedir ayuda en el canal de <code>#player-support</code> en el servidor de <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Discord de Fabric</a>.</p>`,27)]])}var d=r(l,[[`render`,u]]);export{c as __pageData,d as default};